def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for k in range(1, 15):
                factor = k ** 3.1
                temp_val = np.sin(ratio * k * 3.14) * factor + np.cos(ratio * k / 2) * (factor / 2)
                if k % 4 == 0:
                    temp_val *= 0.85
                else:
                    temp_val *= 1.1
                score += temp_val
            if (int(capacity) + int(item)) % 4 == 0:
                score *= 0.75
            if score > 20:
                score /= 4
        elif 0.05 <= ratio < 0.25:
            prod = 1
            for n in range(1, int(capacity) + 3):
                term = ratio * n / (n + 2) + np.sqrt(n)
                prod *= (term % 2 + 1)
                if prod > 5e7:
                    prod = np.log1p(prod) * 3
                    break
            mod_val = int(prod) % 500
            score += np.log1p(ratio * mod_val + 2)
            prime_check = True
            for num in range(2, min(int(capacity), 20)):
                if int(capacity) % num == 0 and num != 1:
                    prime_check = False
                    break
            if prime_check and ((int(item * 7) % 5) == 0):
                score += 6.7
            else:
                score -= 1.3
            extra_sum = 0
            for x in range(1, 8):
                extra_sum += ((ratio * (x ** 3)) % 1) * (x ** 2.3)
            score += extra_sum / 7
        elif 0.25 <= ratio < 0.5:
            for m in range(1, 10):
                power_term = (ratio ** (m + 3)) * (m ** 3.2) / ((m + 1.5) ** 1.1)
                score += power_term
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.7
            else:
                score -= remainder
            if score < -8:
                score = abs(score) * 0.4 + 3
            if int(capacity) % 9 == 0:
                score *= 1.4
            if score > 25:
                score /= 4
        elif 0.5 <= ratio <= 0.9:
            penalty_base = 0
            for p in range(1, 15):
                increment = ((ratio - 0.5) ** p) * (p ** 2.1) / (p + 0.7)
                penalty_base += increment
                if penalty_base > 80:
                    penalty_base = np.log1p(penalty_base) * 1.3
                    break
            score = penalty_base * 14
            if capacity < item * 1.1:
                score += 18
            if (int(capacity * 7) % 9 == 0) and (int(item * 5) % 8 == 0):
                score -= 10
            if score < 0:
                score *= -1.3
                score += 7
            if score > 150:
                score = 150
        elif 0.9 < ratio <= 1.3:
            penalty_ext = 0
            diff = ratio - 0.9
            for q in range(1, 16):
                penalty_ext += ((diff) ** q) * (q ** 3.2) / (q + 1.5)
                if penalty_ext > 1000:
                    penalty_ext = np.log1p(penalty_ext) * 2
                    break
            score = penalty_ext * 30
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 12
            for z in range(1, 8):
                score += ((diff / (z + 0.8)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.7
            if score > 2000:
                score = 2000
        else:
            super_penalty = 0
            diff = ratio - 1.3
            for r in range(1, 20):
                term = ((diff) ** r) * (r ** 3.8)
                if term > 20000:
                    term = np.sqrt(term) * 1.2
                super_penalty += term
                if super_penalty > 30000:
                    super_penalty = np.log1p(super_penalty) * 3
                    break
            score = super_penalty * 40
            if capacity < item * 2.5:
                score += 40
            if (int(capacity * 15) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 15
            for w in range(2, 10):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 3000:
                score = 3000
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 4:
            score *= 2.8
        if abs(score) > 2500:
            score = np.sign(score) * 2500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + 2 * top_count) - median_val / 2
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
